import{_ as t}from"./chunks/keycloak-index.BcFN40Up.js";import{_ as o,o as e,c as r,ag as a}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"Keycloak Sandbox 双沙箱环境","description":"","frontmatter":{},"headers":[{"level":1,"title":"Keycloak Sandbox 双沙箱环境","slug":"keycloak-sandbox-双沙箱环境","link":"#keycloak-sandbox-双沙箱环境","children":[{"level":2,"title":"项目简介","slug":"项目简介","link":"#项目简介","children":[]},{"level":2,"title":"沙箱类型","slug":"沙箱类型","link":"#沙箱类型","children":[{"level":3,"title":"Docker 版沙箱","slug":"docker-版沙箱","link":"#docker-版沙箱","children":[]},{"level":3,"title":"Release 版沙箱","slug":"release-版沙箱","link":"#release-版沙箱","children":[]}]},{"level":2,"title":"版本对比","slug":"版本对比","link":"#版本对比","children":[]},{"level":2,"title":"核心功能","slug":"核心功能","link":"#核心功能","children":[]},{"level":2,"title":"技术支持","slug":"技术支持","link":"#技术支持","children":[]},{"level":2,"title":"快速开始","slug":"快速开始","link":"#快速开始","children":[]},{"level":2,"title":"注意事项","slug":"注意事项","link":"#注意事项","children":[]},{"level":2,"title":"免责声明","slug":"免责声明","link":"#免责声明","children":[]}]}],"relativePath":"dev/keycloak-sandbox/index.md","filePath":"dev/keycloak-sandbox/index.md"}'),n={name:"dev/keycloak-sandbox/index.md"};function i(s,l,d,c,g,k){return e(),r("div",null,[...l[0]||(l[0]=[a('<h1 id="keycloak-sandbox-双沙箱环境" tabindex="-1">Keycloak Sandbox 双沙箱环境 <a class="header-anchor" href="#keycloak-sandbox-双沙箱环境" aria-label="Permalink to &quot;Keycloak Sandbox 双沙箱环境&quot;">​</a></h1><h2 id="项目简介" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介" aria-label="Permalink to &quot;项目简介&quot;">​</a></h2><p>Keycloak Sandbox 沙箱项目是面向开发者打造的一站式 Keycloak SPI 开发环境，支持快速开发、测试和部署 Keycloak 服务提供者接口（SPI）。本项目提供完整的开发基座、多版本支持和内置沙箱环境，旨在帮助开发者快速构建、定制和部署符合企业需求的 Keycloak 扩展。</p><p>项目基于 Maven 多模块架构，提供 Docker 版和 Release 版两种沙箱环境，支持任意 Keycloak 版本切换，同时内置多个 SPI 开发示例，大幅提升 Keycloak 扩展开发效率。</p><h2 id="沙箱类型" tabindex="-1">沙箱类型 <a class="header-anchor" href="#沙箱类型" aria-label="Permalink to &quot;沙箱类型&quot;">​</a></h2><p>根据您的需求，选择适合的沙箱环境：</p><h3 id="docker-版沙箱" tabindex="-1">Docker 版沙箱 <a class="header-anchor" href="#docker-版沙箱" aria-label="Permalink to &quot;Docker 版沙箱&quot;">​</a></h3><ul><li><strong>功能</strong>：基于 Docker 容器运行 Keycloak 服务，适合需要隔离环境的开发者</li><li><strong>环境要求</strong>：需要安装 Docker 和 Docker Compose</li><li><strong>核心特性</strong>：支持任意 Keycloak 版本，一键启动和停止，环境隔离性好</li><li><strong>使用方式</strong>：通过 IDE 直接运行启动类或使用 Maven 命令</li><li><strong>界面预览</strong>：</li></ul><p><img src="'+t+'" alt="Keycloak Sandbox 界面"></p><ul><li><strong>文档链接</strong>：<a href="./keycloak-sandbox.html">Keycloak Sandbox 文档</a></li></ul><h3 id="release-版沙箱" tabindex="-1">Release 版沙箱 <a class="header-anchor" href="#release-版沙箱" aria-label="Permalink to &quot;Release 版沙箱&quot;">​</a></h3><ul><li><strong>功能</strong>：基于本地安装的 Keycloak 运行服务，适合需要更直接访问文件系统的开发者</li><li><strong>环境要求</strong>：仅需要 JDK 和 Maven</li><li><strong>核心特性</strong>：支持任意 Keycloak 版本，一键启动和停止，访问文件系统方便</li><li><strong>使用方式</strong>：通过 IDE 直接运行启动类或使用 Maven 命令</li><li><strong>界面预览</strong>：</li></ul><p><img src="'+t+'" alt="Keycloak Sandbox 界面"></p><ul><li><strong>文档链接</strong>：<a href="./keycloak-sandbox.html">Keycloak Sandbox 文档</a></li></ul><h2 id="版本对比" tabindex="-1">版本对比 <a class="header-anchor" href="#版本对比" aria-label="Permalink to &quot;版本对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比项</th><th>Docker 版沙箱</th><th>Release 版沙箱</th></tr></thead><tbody><tr><td><strong>环境要求</strong></td><td>Docker + Docker Compose</td><td>JDK + Maven</td></tr><tr><td><strong>启动速度</strong></td><td>首次启动较慢（需要下载镜像）</td><td>首次启动较慢（需要下载 Release 包）</td></tr><tr><td><strong>环境隔离</strong></td><td>好</td><td>一般</td></tr><tr><td><strong>文件系统访问</strong></td><td>较复杂（需要挂载卷）</td><td>简单（直接访问本地文件）</td></tr><tr><td><strong>配置灵活性</strong></td><td>高（通过 Docker Compose 配置）</td><td>高（直接修改配置文件）</td></tr><tr><td><strong>适用场景</strong></td><td>隔离环境开发、多版本并行测试</td><td>本地开发、需要频繁修改配置</td></tr></tbody></table><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><p><strong>Keycloak Sandbox 沙箱项目</strong></p><p><strong>核心开发功能：</strong></p><p>专为企业级 Keycloak 扩展开发深度打造，一站式重构 SPI 开发流程，开箱即用、零门槛适配多版本 Keycloak，完美支撑开发、测试、部署全流程需求，解决 Keycloak 版本切换复杂、SPI 开发调试困难等核心痛点。</p><ul><li><strong>01：多版本 Keycloak 支持</strong> — 全局仅需在一个地方配置 Keycloak 版本，实现全局版本控制，开发者可根据项目需求灵活选择目标版本，无需担心版本兼容性问题，大幅提升开发适配效率。</li><li><strong>02：双沙箱环境集成</strong> — 内置两个沙箱环境：Docker 版沙箱和 Release 版沙箱，均支持启动类和停止类，可在 IDE 中右键直接运行 main 方法，方便快速开发和启动。</li><li><strong>03：SPI 一键打包发布</strong> — 提供 SPI 一键打包功能，支持打包类，可在 IDE 中右键直接运行 main 方法，自动将开发的 SPI 打包为 JAR 并发布到指定的沙箱环境，简化部署流程。</li><li><strong>04：内置 SPI 开发示例</strong> — 提供 3 个 SPI 开发示例：事件监听器扩展、国密算法扩展、用户存储扩展，覆盖 Keycloak 常见扩展场景，为开发者提供参考实现。</li><li><strong>05：标准化项目结构</strong> — 采用 Maven 多模块架构，清晰分离沙箱环境和扩展模块，便于项目管理和代码维护。</li></ul><h2 id="技术支持" tabindex="-1">技术支持 <a class="header-anchor" href="#技术支持" aria-label="Permalink to &quot;技术支持&quot;">​</a></h2><ul><li><strong>技术支持</strong>：北京必码科技工作室</li><li><strong>官方文档</strong>：<a href="https://bima.cc" target="_blank" rel="noreferrer">https://bima.cc</a></li><li><strong>官方店铺</strong>：<a href="https://bima.taobao.com" target="_blank" rel="noreferrer">https://bima.taobao.com</a></li><li><strong>联系邮箱</strong>：<a href="mailto:bima.cc@qq.com" target="_blank" rel="noreferrer">bima.cc@qq.com</a></li><li><strong>联系微信</strong>：e18929958</li></ul><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h2><ol><li><strong>配置 Keycloak 版本</strong>：在父 <code>pom.xml</code> 文件中配置目标 Keycloak 版本</li><li><strong>选择沙箱环境</strong>：根据您的需求选择 Docker 版或 Release 版沙箱</li><li><strong>启动沙箱</strong>：通过 IDE 直接运行启动类或使用 Maven 命令启动沙箱</li><li><strong>开发 SPI 扩展</strong>：选择 SPI 示例模块，修改或添加 SPI 实现</li><li><strong>打包发布</strong>：使用扩展打包模块打包并发布 SPI 到沙箱环境</li><li><strong>访问服务</strong>：通过 <code>http://localhost:8080</code> 访问 Keycloak 服务</li><li><strong>测试验证</strong>：在管理控制台中配置并测试 SPI 功能</li></ol><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li><strong>环境要求</strong>：确保 JDK 版本为 11+，Maven 版本为 3.9+（Docker 版沙箱还需要 Docker 环境）</li><li><strong>版本配置</strong>：根据项目需求在父 <code>pom.xml</code> 文件中配置合适的 Keycloak 版本</li><li><strong>首次启动</strong>：首次启动沙箱时，会自动下载对应版本的 Docker 镜像或 Release 发行包，可能需要一些时间</li><li><strong>默认账号</strong>：沙箱环境的默认管理员账号为用户名 <code>root</code>，密码 <code>root</code></li><li><strong>开发测试</strong>：本项目仅用于开发和测试目的，不建议在生产环境中使用</li><li><strong>扩展定制</strong>：可以根据业务需求添加新的 SPI 扩展模块，或修改现有示例</li><li><strong>版本切换</strong>：切换 Keycloak 版本后，需要重新构建项目并启动沙箱环境</li><li><strong>配置修改</strong>：根据沙箱类型，修改相应的配置文件以适应您的环境</li><li><strong>技术支持</strong>：如有技术问题，可联系北京必码科技工作室获取支持</li><li><strong>合规使用</strong>：确保在使用本项目时遵守相关法律法规和行业规范</li></ul><h2 id="免责声明" tabindex="-1">免责声明 <a class="header-anchor" href="#免责声明" aria-label="Permalink to &quot;免责声明&quot;">​</a></h2><p>本项目基于 GitHub 开源软件进行定制化开发，旨在为企业和开发者提供更便捷的项目基座解决方案。使用本项目时，请务必了解以下免责声明：</p><ol><li><strong>开源基础</strong>：本项目基于 GitHub 开源软件构建，遵循原开源协议的相关规定。</li><li><strong>定制开发</strong>：我们对原开源软件进行了定制和扩展，以提供更优质的开发体验和功能支持。</li><li><strong>责任限制</strong>：对于使用本项目可能产生的任何直接或间接的经济损失、数据丢失或其他问题，北京必码科技工作室不承担任何责任。</li><li><strong>使用建议</strong>：在生产环境中使用本项目前，请进行充分的测试和验证，确保其符合您的业务需求和安全要求。</li><li><strong>技术支持</strong>：我们提供技术支持服务，但不保证解决所有可能出现的问题。</li><li><strong>合规使用</strong>：用户应确保在使用本项目时遵守相关法律法规和行业规范，不得用于任何违法或违规用途。</li></ol>',30)])])}const m=o(n,[["render",i]]);export{u as __pageData,m as default};
